select 
from jst_mall_goods g
where g.del_flag = '0'

    and g.goods_name like concat('%', #{goodsName}, '%')


    and g.goods_type = #{goodsType}


    and g.status = #{status}


    and g.role_limit = #{roleLimit}

order by g.create_time desc, g.goods_id desc

mapper.update:
update jst_mall_goods
set status = #{targetStatus},
    update_by = #{updateBy},
    update_time = #{updateTime}
where goods_id = #{goodsId}
  and status = #{expectedStatus}
  and del_flag = '0'

update jst_mall_goods
set del_flag = '2',
    update_by = #{updateBy},
    update_time = #{updateTime}
where goods_id = #{goodsId}
  and del_flag = '0'

update jst_mall_goods
set stock = case when stock = -1 then -1 else stock + #{quantity} end,
    update_by = #{updateBy},
    update_time = #{updateTime}
where goods_id = #{goodsId}
  and del_flag = '0'
